    private ActiveSession? _sessionToRevoke;
    private bool _showRevokeDialog;
    private string? _message;
    private bool _messageIsError;

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task HandleRevoke(string sessionId)
    {
        try
        {
            await OnRevoke.InvokeAsync(sessionId);
            _message = "Session revoked successfully.";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to revoke session: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _showRevokeDialog = false;
            _sessionToRevoke = null;
        }
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

