<div class="card mb-4">
    <div class="card-header d-flex align-items-center justify-content-between"
         role="button" @onclick="() => _expanded = !_expanded">
        <h6 class="mb-0">Change Password</h6>
        <span class="expand-icon">@(_expanded ? "▲" : "▼")</span>
    </div>
    @if (_expanded)
    {
        <div class="card-body">
            @if (LastPasswordChange.HasValue)
            {
                <p class="text-muted small">
                    Last changed: @LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
