                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public DateTime? LastPasswordChange { get; set; }
    [Parameter] public EventCallback<(string currentPassword, string newPassword)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    private async Task UpdatePassword()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _message = "Current password is required.";
            _messageIsError = true;
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "New password is required.";
            _messageIsError = true;
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _messageIsError = true;
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _message = "Password updated successfully!";
            _messageIsError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed to change password: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}
"}

