@namespace sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Components.Pages.Settings
@using sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Services

<div class="settings-section">
    <h3>Notifications</h3>
    <p class="text-muted">Configure how you receive notifications</p>

    @if (_loading)
    {
        <div class="d-flex justify-content-center p-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="mb-4">
            <h5>General</h5>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@_emailNotifications"
                       @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="emailNotif">
                    Email Notifications
                    <small class="d-block text-muted">Receive notifications via email</small>
                </label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@_pushNotifications"
                       @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="pushNotif">
                    Push Notifications
                    <small class="d-block text-muted">Receive push notifications in your browser</small>
                </label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@_weeklyDigest"
                       @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="weeklyDigest">
                    Weekly Digest
                    <small class="d-block text-muted">Receive a weekly summary of activity</small>
                </label>
            </div>
        </div>

        <div class="mb-4">
            <h5>Muted Channels</h5>
            <p class="text-muted small">Check channels to mute them</p>
            @if (_allChannels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                <div class="list-group">
                    @foreach (var channel in _allChannels)
                    {
                        var isMuted = _mutedChannels.Contains(channel);
                        <label class="list-group-item d-flex align-items-center gap-2">
                            <input class="form-check-input mt-0" type="checkbox"
                                   checked="@isMuted"
                                   @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                            <span>@channel</span>
                            @if (isMuted)
                            {
                                <span class="badge bg-secondary ms-auto">Muted</span>
                            }
                        </label>
                    }
                </div>
            }
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary" @onclick="SavePreferences" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    // Simulated available channels — in production these would come from a service
    private readonly List<string> _allChannels = ["general", "announcements", "engineering", "design", "marketing", "support"];

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = prefs.EmailNotifications;
            _pushNotifications = prefs.PushNotifications;
            _weeklyDigest = prefs.WeeklyDigest;
            _mutedChannels = [.. prefs.MutedChannels];
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        _saving = true;
        _message = null;
        try
        {
            var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _message = "Notification preferences saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save preferences: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

