@namespace sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Components.Pages.Settings
@using sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Services

@if (Session is not null && Visible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the following session?</p>
                    <ul class="list-unstyled ms-3">
                        <li><strong>Device:</strong> @Session.Device</li>
                        <li><strong>Location:</strong> @Session.Location</li>
                        <li><strong>Last active:</strong> @Session.LastActive.ToString("g")</li>
                    </ul>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Revoke
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public bool Visible { get; set; }
    [Parameter] public EventCallback<string> OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private bool _revoking;

    private async Task Confirm()
    {
        if (Session is null) return;
        _revoking = true;
        try
        {
            await OnConfirm.InvokeAsync(Session.Id);
        }
        finally
        {
            _revoking = false;
        }
    }

    private async Task Cancel()
    {
        await OnCancel.InvokeAsync();
    }
}

