@namespace sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Components.Pages.Settings
@using sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Services

<div class="mb-4">
    <h5>Active Sessions</h5>
    @if (Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        var isCurrent = session.Id == CurrentSessionId;
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-success ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => RequestRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

<RevokeSessionDialog Session="_sessionToRevoke"
                      Visible="_showRevokeDialog"
                      OnConfirm="HandleRevoke"
                      OnCancel="CancelRevoke" />

@if (!string.IsNullOrEmpty(_message))
{
    <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
        @_message
        <button type="button" class="btn-close" @onclick="() => _message = null"></button>
    </div>
}

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _showRevokeDialog;
    private string? _message;
    private bool _messageIsError;

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task HandleRevoke(string sessionId)
    {
        try
        {
            await OnRevoke.InvokeAsync(sessionId);
            _message = "Session revoked successfully.";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to revoke session: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _showRevokeDialog = false;
            _sessionToRevoke = null;
        }
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

