@namespace sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Components.Pages.Settings
@using sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Services

<div class="settings-section">
    <h3>Security</h3>
    <p class="text-muted">Manage your account security</p>

    @if (_loading)
    {
        <div class="d-flex justify-content-center p-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="mb-4">
            <h5>Two-Factor Authentication</h5>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled" disabled />
                    <label class="form-check-label" for="twoFactor">
                        Two-Factor Authentication
                    </label>
                </div>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
        </div>

        <ChangePasswordPanel LastPasswordChange="_lastPasswordChange"
                             OnChangePassword="HandleChangePassword" />

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_currentSessionId"
                             OnRevoke="HandleRevokeSession" />
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private bool _loading = true;

    // Assume the first session is the current one
    private string? _currentSessionId;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = settings.TwoFactorEnabled;
            _lastPasswordChange = settings.LastPasswordChange;
            _sessions = settings.Sessions;
            _currentSessionId = _sessions.FirstOrDefault()?.Id;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleChangePassword((string currentPassword, string newPassword) args)
    {
        await SettingsService.ChangePasswordAsync(args.currentPassword, args.newPassword);
        _lastPasswordChange = DateTime.UtcNow;
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
    }
}

@namespace sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Components.Pages.Settings
@using sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Services

<div class="settings-section">
    <h3>Appearance</h3>
    <p class="text-muted">Customize how the application looks</p>

    @if (_loading)
    {
        <div class="d-flex justify-content-center p-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                <div class="mb-4">
                    <h5>Theme</h5>
                    <div class="d-flex gap-3">
                        @foreach (var theme in _themes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="theme-@theme" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="theme-@theme">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h5>Font Size</h5>
                    <div class="d-flex gap-3">
                        @foreach (var size in _fontSizes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="fs-@size" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="fs-@size">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h5>Language</h5>
                    <select class="form-select" style="max-width: 300px;"
                            @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang.Key">@lang.Value</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <h5>Compact Mode</h5>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        <label class="form-check-label" for="compactMode">
                            Reduce spacing and padding
                        </label>
                    </div>
                </div>

                @if (!string.IsNullOrEmpty(_message))
                {
                    <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                        @_message
                        <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                    </div>
                }

                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Save
                </button>
            </div>

            <div class="col-md-5">
                <h5>Preview</h5>
                <div class="appearance-preview @GetPreviewClasses()" style="@GetPreviewStyles()">
                    <div class="preview-header">
                        <strong>Sample Header</strong>
                    </div>
                    <div class="preview-body">
                        <p>This is how your content will look with the selected settings.</p>
                        <button class="btn btn-sm @(_theme == "Dark" ? "btn-light" : "btn-primary")">
                            Sample Button
                        </button>
                    </div>
                    <div class="preview-sidebar">
                        <ul>
                            <li>Menu Item 1</li>
                            <li>Menu Item 2</li>
                            <li>Menu Item 3</li>
                        </ul>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語",
        ["zh"] = "中文"
    };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        finally
        {
            _loading = false;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_theme == "Dark") classes.Add("preview-dark");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private string GetPreviewStyles()
    {
        var size = _fontSize switch
        {
            "Small" => "12px",
            "Large" => "18px",
            _ => "14px"
        };
        return $"font-size: {size};";
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        _message = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _message = "Appearance settings saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save settings: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

@page "/settings"
@namespace sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Components.Pages.Settings
@using sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionSelected="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection SettingsService="SettingsService" />
                break;
            case "Notifications":
                <NotificationsSection SettingsService="SettingsService" />
                break;
            case "Security":
                <SecuritySection SettingsService="SettingsService" />
                break;
            case "Appearance":
                <AppearanceSection SettingsService="SettingsService" />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

/* ===== Settings Dashboard Layout ===== */

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 120px);
    gap: 0;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
}

/* ===== Sidebar ===== */

.settings-sidebar {
    width: 240px;
    min-width: 240px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
}

.settings-sidebar .nav {
    padding-top: 0.5rem;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    color: #495057;
    background: none;
    border: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    cursor: pointer;
    transition: all 0.15s ease;
    border-left: 3px solid transparent;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background: #fff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.section-icon {
    font-size: 1.1rem;
    width: 1.5rem;
    text-align: center;
}

/* ===== Content ===== */

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
    font-weight: 600;
}

.settings-section > .text-muted {
    margin-bottom: 1.5rem;
}

/* ===== Profile Avatar ===== */

.avatar-preview {
    text-align: center;
}

.avatar-container {
    width: 150px;
    height: 150px;
    margin: 0 auto;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f8f9fa;
}

.avatar-image {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    color: #6c757d;
    font-size: 0.9rem;
}

/* ===== Expand Icon ===== */

.expand-icon {
    font-size: 0.75rem;
    color: #6c757d;
}

/* ===== Appearance Preview ===== */

.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    transition: all 0.2s ease;
    background: #fff;
    color: #212529;
}

.appearance-preview.preview-dark {
    background: #1e1e1e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
    background: rgba(0, 0, 0, 0.03);
}

.preview-dark .preview-header {
    border-bottom-color: #444;
    background: rgba(255, 255, 255, 0.05);
}

.preview-body {
    padding: 1rem;
}

.preview-compact .preview-body {
    padding: 0.5rem;
}

.preview-compact .preview-header {
    padding: 0.4rem 0.75rem;
}

.preview-sidebar {
    padding: 0.5rem 1rem;
    border-top: 1px solid #dee2e6;
    background: rgba(0, 0, 0, 0.02);
}

.preview-dark .preview-sidebar {
    border-top-color: #444;
    background: rgba(255, 255, 255, 0.03);
}

.preview-sidebar ul {
    list-style: none;
    padding: 0;
    margin: 0;
}

.preview-sidebar li {
    padding: 0.25rem 0;
}

.preview-compact .preview-sidebar li {
    padding: 0.1rem 0;
}

@namespace sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Components.Pages.Settings
@using sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Services

<div class="settings-section">
    <h3>Security</h3>
    <p class="text-muted">Manage your account security</p>

    @if (_loading)
    {
        <div class="d-flex justify-content-center p-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="mb-4">
            <h5>Two-Factor Authentication</h5>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled" disabled />
                    <label class="form-check-label" for="twoFactor">
                        Two-Factor Authentication
                    </label>
                </div>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
        </div>

        <ChangePasswordPanel LastPasswordChange="_lastPasswordChange"
                             OnChangePassword="HandleChangePassword" />

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_currentSessionId"
                             OnRevoke="HandleRevokeSession" />
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private bool _loading = true;

    // Assume the first session is the current one
    private string? _currentSessionId;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = settings.TwoFactorEnabled;
            _lastPasswordChange = settings.LastPasswordChange;
            _sessions = settings.Sessions;
            _currentSessionId = _sessions.FirstOrDefault()?.Id;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleChangePassword((string currentPassword, string newPassword) args)
    {
        await SettingsService.ChangePasswordAsync(args.currentPassword, args.newPassword);
        _lastPasswordChange = DateTime.UtcNow;
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
    }
}

@namespace sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Components.Pages.Settings
@using sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Services

<div class="settings-section">
    <h3>Appearance</h3>
    <p class="text-muted">Customize how the application looks</p>

    @if (_loading)
    {
        <div class="d-flex justify-content-center p-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                <div class="mb-4">
                    <h5>Theme</h5>
                    <div class="d-flex gap-3">
                        @foreach (var theme in _themes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="theme-@theme" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="theme-@theme">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h5>Font Size</h5>
                    <div class="d-flex gap-3">
                        @foreach (var size in _fontSizes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="fs-@size" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="fs-@size">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h5>Language</h5>
                    <select class="form-select" style="max-width: 300px;"
                            @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang.Key">@lang.Value</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <h5>Compact Mode</h5>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        <label class="form-check-label" for="compactMode">
                            Reduce spacing and padding
                        </label>
                    </div>
                </div>

                @if (!string.IsNullOrEmpty(_message))
                {
                    <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                        @_message
                        <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                    </div>
                }

                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Save
                </button>
            </div>

            <div class="col-md-5">
                <h5>Preview</h5>
                <div class="appearance-preview @GetPreviewClasses()" style="@GetPreviewStyles()">
                    <div class="preview-header">
                        <strong>Sample Header</strong>
                    </div>
                    <div class="preview-body">
                        <p>This is how your content will look with the selected settings.</p>
                        <button class="btn btn-sm @(_theme == "Dark" ? "btn-light" : "btn-primary")">
                            Sample Button
                        </button>
                    </div>
                    <div class="preview-sidebar">
                        <ul>
                            <li>Menu Item 1</li>
                            <li>Menu Item 2</li>
                            <li>Menu Item 3</li>
                        </ul>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語",
        ["zh"] = "中文"
    };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        finally
        {
            _loading = false;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_theme == "Dark") classes.Add("preview-dark");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private string GetPreviewStyles()
    {
        var size = _fontSize switch
        {
            "Small" => "12px",
            "Large" => "18px",
            _ => "14px"
        };
        return $"font-size: {size};";
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        _message = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _message = "Appearance settings saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save settings: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

