.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    transition: all 0.2s ease;
    background: #fff;
    color: #212529;
}

.appearance-preview.preview-dark {
    background: #1e1e1e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
    background: rgba(0, 0, 0, 0.03);
