@namespace sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Components.Pages.Settings
@using sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Services

<div class="settings-section">
    <h3>Appearance</h3>
    <p class="text-muted">Customize how the application looks</p>

    @if (_loading)
    {
        <div class="d-flex justify-content-center p-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                <div class="mb-4">
                    <h5>Theme</h5>
                    <div class="d-flex gap-3">
                        @foreach (var theme in _themes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="theme-@theme" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="theme-@theme">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h5>Font Size</h5>
                    <div class="d-flex gap-3">
                        @foreach (var size in _fontSizes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="fs-@size" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="fs-@size">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h5>Language</h5>
                    <select class="form-select" style="max-width: 300px;"
                            @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang.Key">@lang.Value</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <h5>Compact Mode</h5>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        <label class="form-check-label" for="compactMode">
                            Reduce spacing and padding
                        </label>
                    </div>
                </div>

                @if (!string.IsNullOrEmpty(_message))
                {
                    <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                        @_message
                        <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                    </div>
                }

                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Save
                </button>
            </div>

            <div class="col-md-5">
                <h5>Preview</h5>
                <div class="appearance-preview @GetPreviewClasses()" style="@GetPreviewStyles()">
                    <div class="preview-header">
                        <strong>Sample Header</strong>
                    </div>
                    <div class="preview-body">
                        <p>This is how your content will look with the selected settings.</p>
                        <button class="btn btn-sm @(_theme == "Dark" ? "btn-light" : "btn-primary")">
                            Sample Button
                        </button>
                    </div>
                    <div class="preview-sidebar">
                        <ul>
                            <li>Menu Item 1</li>
                            <li>Menu Item 2</li>
                            <li>Menu Item 3</li>
                        </ul>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

