@page "/settings"
@namespace sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Components.Pages.Settings
@using sv_0fbcef1ba2f445d0ab07f4f5cfe17c3e.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionSelected="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection SettingsService="SettingsService" />
                break;
            case "Notifications":
                <NotificationsSection SettingsService="SettingsService" />
                break;
            case "Security":
                <SecuritySection SettingsService="SettingsService" />
                break;
            case "Appearance":
                <AppearanceSection SettingsService="SettingsService" />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

/* ===== Settings Dashboard Layout ===== */

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 120px);
    gap: 0;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
}

/* ===== Sidebar ===== */

.settings-sidebar {
    width: 240px;
    min-width: 240px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
}

.settings-sidebar .nav {
    padding-top: 0.5rem;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    color: #495057;
    background: none;
    border: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    cursor: pointer;
    transition: all 0.15s ease;
    border-left: 3px solid transparent;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background: #fff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.section-icon {
    font-size: 1.1rem;
    width: 1.5rem;
    text-align: center;
}

/* ===== Content ===== */

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
    font-weight: 600;
}

.settings-section > .text-muted {
    margin-bottom: 1.5rem;
}

/* ===== Profile Avatar ===== */

.avatar-preview {
    text-align: center;
}

.avatar-container {
    width: 150px;
    height: 150px;
    margin: 0 auto;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f8f9fa;
}

.avatar-image {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    color: #6c757d;
    font-size: 0.9rem;
}

/* ===== Expand Icon ===== */

.expand-icon {
    font-size: 0.75rem;
    color: #6c757d;
}

/* ===== Appearance Preview ===== */

.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    transition: all 0.2s ease;
    background: #fff;
    color: #212529;
}

.appearance-preview.preview-dark {
    background: #1e1e1e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
    background: rgba(0, 0, 0, 0.03);
}

.preview-dark .preview-header {
    border-bottom-color: #444;
    background: rgba(255, 255, 255, 0.05);
}

.preview-body {
    padding: 1rem;
}

.preview-compact .preview-body {
    padding: 0.5rem;
}

.preview-compact .preview-header {
    padding: 0.4rem 0.75rem;
}

.preview-sidebar {
    padding: 0.5rem 1rem;
    border-top: 1px solid #dee2e6;
    background: rgba(0, 0, 0, 0.02);
}

.preview-dark .preview-sidebar {
    border-top-color: #444;
    background: rgba(255, 255, 255, 0.03);
}

.preview-sidebar ul {
    list-style: none;
    padding: 0;
    margin: 0;
}

.preview-sidebar li {
    padding: 0.25rem 0;
}

.preview-compact .preview-sidebar li {
    padding: 0.1rem 0;
}

